import React, { createContext, useState, useContext, useEffect } from 'react';
import * as SecureStore from 'expo-secure-store';
import { router } from 'expo-router';

interface User {
  id: string;
  code: string;
  name: string;
  role: string;
  email: string;
  phone: string;
  classes: Array<{ id: string; name: string; section: string }>;
  token: string;
  employeeId?: string;
}

interface AuthContextType {
  user: User | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  isFirstLogin: boolean;
  login: (userData: User) => Promise<void>;
  logout: () => Promise<void>;
  completeFirstLogin: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

const TOKEN_KEY = 'user_token';
const USER_KEY = 'user_data';
const FIRST_LOGIN_KEY = 'first_login_completed';

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isFirstLogin, setIsFirstLogin] = useState(false);

  useEffect(() => {
    loadStoredData();
  }, []);

  const loadStoredData = async () => {
    try {
      const [token, userData] = await Promise.all([
        SecureStore.getItemAsync(TOKEN_KEY),
        SecureStore.getItemAsync(USER_KEY),
      ]);

      if (token && userData) {
        setUser(JSON.parse(userData));
        // Check if user has completed first login
        const firstLoginCompleted = await SecureStore.getItemAsync(FIRST_LOGIN_KEY);
        setIsFirstLogin(!firstLoginCompleted);
      }
    } catch (error) {
      console.error('Error loading stored data:', error);
      // If decryption fails, clear corrupted data
      if (error?.message?.includes('Could not decrypt')) {
        console.log('Clearing corrupted SecureStore data...');
        try {
          await Promise.all([
            SecureStore.deleteItemAsync(TOKEN_KEY).catch(() => {}),
            SecureStore.deleteItemAsync(USER_KEY).catch(() => {}),
            SecureStore.deleteItemAsync(FIRST_LOGIN_KEY).catch(() => {}),
          ]);
        } catch (clearError) {
          console.error('Error clearing corrupted data:', clearError);
        }
      }
    } finally {
      setIsLoading(false);
    }
  };

  const login = async (userData: User) => {
    try {
      await Promise.all([
        SecureStore.setItemAsync(TOKEN_KEY, userData.token),
        SecureStore.setItemAsync(USER_KEY, JSON.stringify(userData)),
      ]);
      setUser(userData);
      // Check if this is first login
      const firstLoginCompleted = await SecureStore.getItemAsync(FIRST_LOGIN_KEY);
      setIsFirstLogin(!firstLoginCompleted);
    } catch (error) {
      console.error('Error storing auth data:', error);
      throw error;
    }
  };

  const completeFirstLogin = async () => {
    try {
      await SecureStore.setItemAsync(FIRST_LOGIN_KEY, 'true');
      setIsFirstLogin(false);
    } catch (error) {
      console.error('Error marking first login complete:', error);
    }
  };

  const logout = async () => {
    try {
      await Promise.all([
        SecureStore.deleteItemAsync(TOKEN_KEY),
        SecureStore.deleteItemAsync(USER_KEY),
        SecureStore.deleteItemAsync(FIRST_LOGIN_KEY),
      ]);
      setUser(null);
      setIsFirstLogin(false);
      router.replace('/login');
    } catch (error) {
      console.error('Error clearing auth data:', error);
    }
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        isAuthenticated: !!user,
        isLoading,
        isFirstLogin,
        login,
        logout,
        completeFirstLogin,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

