import React, { createContext, useState, useContext, useEffect, ReactNode } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';

interface NotificationPreferences {
  attendanceUpdates: boolean;
  leaveRequests: boolean;
  announcements: boolean;
  payslips: boolean;
  substitutions: boolean;
  gatePasses: boolean;
  generalAlerts: boolean;
}

interface NotificationContextType {
  preferences: NotificationPreferences;
  updatePreference: (key: keyof NotificationPreferences, value: boolean) => void;
  resetToDefaults: () => void;
  isLoading: boolean;
}

const NOTIFICATION_STORAGE_KEY = '@staff_app_notification_preferences';

const defaultPreferences: NotificationPreferences = {
  attendanceUpdates: true,
  leaveRequests: true,
  announcements: true,
  payslips: true,
  substitutions: true,
  gatePasses: false,
  generalAlerts: true,
};

const NotificationContext = createContext<NotificationContextType | undefined>(undefined);

export function NotificationProvider({ children }: { children: ReactNode }) {
  const [preferences, setPreferences] = useState<NotificationPreferences>(defaultPreferences);
  const [isLoading, setIsLoading] = useState(true);

  // Load preferences on mount
  useEffect(() => {
    loadPreferences();
  }, []);

  const loadPreferences = async () => {
    try {
      const savedPreferences = await AsyncStorage.getItem(NOTIFICATION_STORAGE_KEY);
      if (savedPreferences) {
        setPreferences(JSON.parse(savedPreferences));
      }
    } catch (error) {
      console.error('Failed to load notification preferences:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const updatePreference = async (key: keyof NotificationPreferences, value: boolean) => {
    try {
      const newPreferences = { ...preferences, [key]: value };
      await AsyncStorage.setItem(NOTIFICATION_STORAGE_KEY, JSON.stringify(newPreferences));
      setPreferences(newPreferences);
    } catch (error) {
      console.error('Failed to update notification preference:', error);
    }
  };

  const resetToDefaults = async () => {
    try {
      await AsyncStorage.setItem(NOTIFICATION_STORAGE_KEY, JSON.stringify(defaultPreferences));
      setPreferences(defaultPreferences);
    } catch (error) {
      console.error('Failed to reset notification preferences:', error);
    }
  };

  return (
    <NotificationContext.Provider value={{ preferences, updatePreference, resetToDefaults, isLoading }}>
      {children}
    </NotificationContext.Provider>
  );
}

export function useNotifications() {
  const context = useContext(NotificationContext);
  if (context === undefined) {
    throw new Error('useNotifications must be used within a NotificationProvider');
  }
  return context;
}

