      `${API_URL}/mobile/teacher/${teacherId}/announcements?limit=${limit}`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch announcements');
    return response.json();
  }

  async getSubstitutions(teacherId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/substitutions?substituteTeacherId=${teacherId}`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch substitutions');
    return response.json();
  }

  async getRemarks(studentId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/students/${studentId}/remarks`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch remarks');
    return response.json();
