    name: string;
    examType: string;
    classId: string;
    startDate: string;
    endDate: string;
    totalMarks: number;
    passingMarks: number;
    subjects: Array<{
      subjectName: string;
      date: string;
      maxMarks: number;
    }>;
  }) {
    const response = await this.fetchWithTimeout(
