      `${API_URL}/results`,
      {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify({ examId, studentId, ...marks }),
      }
    );
    if (!response.ok) throw new Error('Failed to enter marks');
    return response.json();
