import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';
import socketService from '../services/socketService';
import type { StaffProfile, SyncStatus } from '../types/api.types';

interface UseStaffProfileReturn {
  profile: StaffProfile | null;
  syncStatus: SyncStatus;
  isLoading: boolean;
  error: string | null;
  refetch: () => Promise<void>;
}

export function useStaffProfile(): UseStaffProfileReturn {
  const { user } = useAuth();
  const [profile, setProfile] = useState<StaffProfile | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>({
    connected: false,
    syncing: false,
    lastSync: undefined,
    error: undefined,
  });

  // Fetch profile data
  const fetchProfile = useCallback(async () => {
    if (!user?.id) {
      setIsLoading(false);
      return;
    }

    try {
      setIsLoading(true);
      setError(null);
      setSyncStatus(prev => ({ ...prev, syncing: true, error: undefined }));

      const profileData = await api.getStaffProfile(user.id);
      setProfile(profileData);

      setSyncStatus(prev => ({
        ...prev,
        syncing: false,
        lastSync: new Date(),
        error: undefined,
      }));
    } catch (err: any) {
      const errorMessage = err.message || 'Failed to fetch profile';
      setError(errorMessage);
      setSyncStatus(prev => ({
        ...prev,
        syncing: false,
        error: errorMessage,
      }));
    } finally {
      setIsLoading(false);
    }
  }, [user?.id]);

  // Refetch function
  const refetch = useCallback(async () => {
    await fetchProfile();
  }, [fetchProfile]);

  // Handle staff_updated socket event
  const handleStaffUpdate = useCallback((data: any) => {
    console.log('📱 Staff update received:', data);

    // Refresh profile if it's our profile or a general update
    if (data.staffId === user?.id || !data.staffId) {
      fetchProfile();
    }
  }, [user?.id, fetchProfile]);

  // Handle socket connection status changes
  const handleAuthenticated = useCallback(() => {
    setSyncStatus(prev => ({
      ...prev,
      connected: true,
      error: undefined,
    }));
  }, []);

  const handleDisconnected = useCallback(() => {
    setSyncStatus(prev => ({
      ...prev,
      connected: false,
    }));
  }, []);

  const handleConnectError = useCallback((err: any) => {
    setSyncStatus(prev => ({
      ...prev,
      connected: false,
      error: err.message || 'Connection error',
    }));
  }, []);

  // Setup effect
  useEffect(() => {
    if (!user?.id) {
      setIsLoading(false);
      return;
    }

    // Fetch profile on mount
    fetchProfile();

    // Connect to socket
    socketService.connect(user.id, 'staff').then(() => {
      setSyncStatus(prev => ({
        ...prev,
        connected: socketService.isConnected(),
      }));
    }).catch((err) => {
      console.error('Socket connection failed:', err);
      setSyncStatus(prev => ({
        ...prev,
        connected: false,
        error: err.message || 'Socket connection failed',
      }));
    });

    // Subscribe to socket events
    socketService.on('staff_updated', handleStaffUpdate);
    socketService.on('authenticated', handleAuthenticated);
    socketService.on('disconnected', handleDisconnected);
    socketService.on('connect_error', handleConnectError);

    // Cleanup
    return () => {
      socketService.off('staff_updated', handleStaffUpdate);
      socketService.off('authenticated', handleAuthenticated);
      socketService.off('disconnected', handleDisconnected);
      socketService.off('connect_error', handleConnectError);
    };
  }, [user?.id, fetchProfile, handleStaffUpdate, handleAuthenticated, handleDisconnected, handleConnectError]);

  return {
    profile,
    syncStatus,
    isLoading,
    error,
    refetch,
  };
}

