import { useState, useEffect } from 'react';
import * as Notifications from 'expo-notifications';
import { Platform } from 'react-native';
import { useAuth } from '../context/AuthContext';
import notificationApi from '../services/notificationApi';
import Constants from 'expo-constants';
import * as Application from 'expo-application';

export function useNotifications() {
  const { user } = useAuth();
  const [pushToken, setPushToken] = useState<string | null>(null);
  const [notificationPermission, setNotificationPermission] = useState<'granted' | 'denied' | 'undetermined'>('undetermined');

  useEffect(() => {
    setupNotifications();
  }, [user]);

  const setupNotifications = async () => {
    // Configure notification handler
    Notifications.setNotificationHandler({
      handleNotification: async () => ({
        shouldShowAlert: true,
        shouldPlaySound: true,
        shouldSetBadge: true,
      }),
    });

    // Check existing permissions
    const { status: existingStatus } = await Notifications.getPermissionsAsync();
    setNotificationPermission(existingStatus);

    if (existingStatus !== 'granted') {
      // Request permissions
      const { status } = await Notifications.requestPermissionsAsync();
      setNotificationPermission(status);
    }

    if (Platform.OS === 'android') {
      // Set up notification channel for Android
      await Notifications.setNotificationChannelAsync('default-channel-id', {
        name: 'default',
        importance: Notifications.AndroidImportance.MAX,
        vibrationPattern: [0, 250, 250, 250],
        lightColor: '#4F46E5',
      });
    }

    // Register for push notifications
    if (user?.id && notificationPermission === 'granted') {
      await registerForPushNotifications();
    }

    // Add notification received listener
    const foregroundSubscription = Notifications.addNotificationReceivedListener(
      (notification) => {
        console.log('Notification received in foreground:', notification);
      }
    );

    // Add notification response listener (user taps notification)
    const responseSubscription = Notifications.addNotificationResponseReceivedListener(
      (response) => {
        console.log('Notification tapped:', response.notification.request.content.data);
        handleNotificationTap(response.notification.request.content.data);
      }
    );

    return () => {
      foregroundSubscription.remove();
      responseSubscription.remove();
    };
  };

  const registerForPushNotifications = async () => {
    try {
      // Skip push token registration if no valid project ID
      const projectId = Constants.expoConfig?.extra?.eas?.projectId;
      if (!projectId) {
        console.log('Skipping push notifications - no EAS project configured');
        return;
      }

      // Get Expo push token
      const token = await Notifications.getExpoPushTokenAsync({
        projectId,
      });

      setPushToken(token.data);

      // Send token to backend
      await notificationApi.registerPushToken({
        token: token.data,
        platform: Platform.OS as 'ios' | 'android',
        appVersion: '1.0.0',
        osVersion: Platform.Version as string,
        deviceId: Application.androidId || Application.applicationId || 'unknown-device-id',
      });

      console.log('Push token registered successfully');
    } catch (error) {
      console.error('Error registering push token:', error);
    }
  };

  const handleNotificationTap = (data: any) => {
    console.log('Handling notification tap:', data);
    // Navigation will be handled based on notification type
    // This can be integrated with your navigation ref
  };

  const requestPermissions = async () => {
    const { status } = await Notifications.requestPermissionsAsync();
    setNotificationPermission(status);

    if (status === 'granted' && user?.id) {
      await registerForPushNotifications();
    }

    return status;
  };

  return {
    pushToken,
    notificationPermission,
    requestPermissions,
  };
}

