import { useState, useCallback } from 'react';
import { TourStep } from '../components/GuidedTour';

interface UseGuidedTourOptions {
  steps: TourStep[];
  onComplete?: () => void;
}

export function useGuidedTour(options: UseGuidedTourOptions) {
  const { steps, onComplete } = options;
  const [visible, setVisible] = useState(false);
  const [currentStepIndex, setCurrentStepIndex] = useState(0);

  const start = useCallback(() => {
    setCurrentStepIndex(0);
    setVisible(true);
  }, []);

  const close = useCallback(() => {
    setVisible(false);
    setCurrentStepIndex(0);
    onComplete?.();
  }, [onComplete]);

  const onNext = useCallback(() => {
    if (currentStepIndex < steps.length - 1) {
      setCurrentStepIndex((prev) => prev + 1);
    } else {
      close();
    }
  }, [currentStepIndex, steps.length, close]);

  return {
    visible,
    currentStepIndex,
    currentStep: steps[currentStepIndex],
    isLastStep: currentStepIndex === steps.length - 1,
    isFirstStep: currentStepIndex === 0,
    start,
    close,
    onNext,
  };
}

export default useGuidedTour;

