     1→import { io, Socket } from 'socket.io-client';
     2→import Constants from 'expo-constants';
     3→
     4→const API_URL = Constants.expoConfig?.extra?.apiUrl || 'http://localhost:3001/api';
     5→const SOCKET_URL = API_URL.replace('/api', '');
     6→
     7→type SocketEvent =
     8→  | 'authenticated'
     9→  | 'disconnected'
    10→  | 'connect_error'
    11→  | 'error'
    12→  | 'new_message'
    13→  | 'message_notification'
    14→  | 'user_typing'
    15→  | 'message_read'
    16→  | 'messages_read'
    17→  | 'user_status'
    18→  | 'joined_conversation'
    19→  | 'message_edited'
    20→  | 'message_reacted'
    21→  | 'message_pinned'
    22→  | 'conversation_pinned'
    23→  | 'conversation_muted'
    24→  | 'conversation_deleted'
    25→  | 'homework_created'
    26→  | 'leave_status_updated'
    27→  | 'teacher_attendance_marked'
    28→  | 'staff_updated';
    29→
    30→type EventCallback = (data: any) => void;
    31→
    32→class SocketService {
    33→  private socket: Socket | null = null;
    34→  private connected: boolean = false;
    35→  private authenticated: boolean = false;
    36→  private userId: string | null = null;
    37→  private userType: 'staff' | 'student' | null = null;
    38→  private listeners: Map<SocketEvent, EventCallback[]> = new Map();
    39→  private reconnectAttempts: number = 0;
    40→  private maxReconnectAttempts: number = 5;
    41→
    42→  connect(userId: string, userType: 'staff' | 'student'): Promise<void> {
    43→    // If already connected and authenticated, reuse the connection
    44→    if (this.socket?.connected && this.authenticated) {
    45→      console.log('✅ Socket already connected and authenticated - reusing connection');
    46→      return Promise.resolve();
    47→    }
    48→
    49→    // If socket exists but not connected, don't create a new one - let it reconnect
    50→    if (this.socket && !this.socket.connected) {
    51→      console.log('⏳ Socket exists but disconnected - waiting for reconnection...');
    52→      return new Promise((resolve, reject) => {
    53→        const timeout = setTimeout(() => {
    54→          reject(new Error('Reconnection timeout'));
    55→        }, 5000);
    56→
    57→        this.socket!.once('authenticated', () => {
    58→          clearTimeout(timeout);
    59→          resolve();
    60→        });
    61→      });
    62→    }
    63→
    64→    return new Promise((resolve, reject) => {
    65→      console.log('🔌 Creating new Socket.IO connection:', SOCKET_URL);
    66→
    67→      this.socket = io(SOCKET_URL, {
    68→        transports: ['websocket', 'polling'],
    69→        reconnection: true,
    70→        reconnectionDelay: 1000,
    71→        reconnectionAttempts: this.maxReconnectAttempts,
    72→        timeout: 10000,
    73→      });
    74→
    75→      this.userId = userId;
    76→      this.userType = userType;
    77→
    78→      // Connection timeout
    79→      const connectionTimeout = setTimeout(() => {
    80→        if (!this.connected || !this.authenticated) {
    81→          console.warn('⚠️ Socket connection/authentication timeout');
    82→          this.disconnect(); // Ensure we clean up if we timeout
    83→          reject(new Error('Connection/Authentication timeout'));
    84→        }
    85→      }, 5000); // Reduced to 5s for faster fallback
    86→
    87→      this.socket.on('connect', () => {
    88→        console.log('✅ Socket connected:', this.socket?.id);
    89→        this.connected = true;
    90→        this.reconnectAttempts = 0;
    91→
    92→        // Authenticate
    93→        this.socket?.emit('authenticate', { userId, userType });
    94→      });
    95→
    96→      this.socket.on('authenticated', (data) => {
    97→        clearTimeout(connectionTimeout);
    98→        console.log('✅ Socket authenticated:', data);
    99→        this.authenticated = true;
   100→        this.emit('authenticated', data);
   101→        resolve();
   102→      });
   103→
   104→      this.socket.on('disconnect', (reason) => {
   105→        console.log('❌ Socket disconnected:', reason);
   106→        this.connected = false;
   107→        this.authenticated = false;
   108→        this.emit('disconnected', { reason });
   109→      });
   110→
   111→      this.socket.on('error', (error) => {
   112→        console.error('❌ Socket error:', error);
   113→        this.emit('error', error);
   114→        reject(error);
   115→      });
   116→
   117→      this.socket.on('connect_error', (error) => {
   118→        console.error('❌ Connection error:', error);
   119→        this.reconnectAttempts++;
   120→
   121→        if (this.reconnectAttempts >= this.maxReconnectAttempts) {
   122→          console.error('❌ Max reconnection attempts reached');
   123→          reject(new Error('Failed to connect after multiple attempts'));
   124→        }
   125→
   126→        this.emit('connect_error', error);
   127→      });
   128→
   129→      // Chat events
   130→      this.socket.on('new_message', (data) => {
   131→        console.log('📨 New message received:', data);
   132→        this.emit('new_message', data);
   133→      });
   134→
   135→      this.socket.on('message_notification', (data) => {
   136→        console.log('🔔 [SOCKET] message_notification event received from server:', data);
   137→        this.emit('message_notification', data);
   138→      });
   139→
   140→      this.socket.on('user_typing', (data) => {
   141→        this.emit('user_typing', data);
   142→      });
   143→
   144→      this.socket.on('message_read', (data) => {
   145→        this.emit('message_read', data);
   146→      });
   147→
   148→      this.socket.on('messages_read', (data) => {
   149→        this.emit('messages_read', data);
   150→      });
   151→
   152→      this.socket.on('user_status', (data) => {
   153→        this.emit('user_status', data);
   154→      });
   155→
   156→      this.socket.on('joined_conversation', (data) => {
   157→        console.log('✅ Joined conversation:', data);
   158→        this.emit('joined_conversation', data);
   159→      });
   160→
   161→      this.socket.on('message_edited', (data) => {
   162→        this.emit('message_edited', data);
   163→      });
   164→
   165→      this.socket.on('message_reacted', (data) => {
   166→        this.emit('message_reacted', data);
   167→      });
   168→
   169→      this.socket.on('message_pinned', (data) => {
   170→        this.emit('message_pinned', data);
   171→      });
   172→
   173→      this.socket.on('conversation_pinned', (data) => {
   174→        this.emit('conversation_pinned', data);
   175→      });
   176→
   177→      this.socket.on('conversation_muted', (data) => {
   178→        this.emit('conversation_muted', data);
   179→      });
   180→
   181→      this.socket.on('conversation_deleted', (data) => {
   182→        this.emit('conversation_deleted', data);
   183→      });
   184→
   185→      // Staff events
   186→      this.socket.on('staff_updated', (data) => {
   187→        console.log('👤 Staff updated event received:', data);
   188→        this.emit('staff_updated', data);
   189→      });
   190→    });
   191→  }
   192→
   193→  disconnect(): void {
   194→    if (this.socket) {
   195→      console.log('🔌 Disconnecting socket...');
   196→      this.socket.disconnect();
   197→      this.socket = null;
   198→      this.connected = false;
   199→      this.authenticated = false;
   200→      this.userId = null;
   201→      this.userType = null;
   202→      this.listeners.clear();
   203→    }
   204→  }
   205→
   206→  // Join a conversation room
   207→  joinConversation(conversationId: string): void {
   208→    if (!this.socket?.connected) {
   209→      console.error('❌ Socket not connected');
   210→      return;
   211→    }
   212→
   213→    console.log('📥 Joining conversation:', conversationId);
   214→    this.socket.emit('join_conversation', { conversationId });
   215→  }
   216→
   217→  // Leave a conversation room
   218→  leaveConversation(conversationId: string): void {
   219→    if (!this.socket?.connected) {
   220→      console.error('❌ Socket not connected');
   221→      return;
   222→    }
   223→
   224→    console.log('📤 Leaving conversation:', conversationId);
   225→    this.socket.emit('leave_conversation', { conversationId });
   226→  }
   227→
   228→  // Send a message
   229→  sendMessage(data: {
   230→    conversationId: string;
   231→    receiverId: string;
   232→    receiverModel: 'Staff' | 'Student';
   233→    content: string;
   234→    type?: 'text' | 'image' | 'file' | 'audio' | 'video';
   235→    fileUrl?: string;
   236→    fileName?: string;
   237→    fileSize?: number;
   238→    replyTo?: {
   239→      messageId: string;
   240→      content: string;
   241→      senderId: string;
   242→      senderName: string;
   243→    };
   244→    forwardedFrom?: any;
   245→  }): void {
   246→    if (!this.socket?.connected) {
   247→      console.error('❌ Socket not connected');
   248→      throw new Error('Socket not connected');
   249→    }
   250→
   251→    console.log('📤 Sending message:', data);
   252→    this.socket.emit('send_message', {
   253→      ...data,
   254→      senderId: this.userId,
   255→      senderModel: this.userType === 'staff' ? 'Staff' : 'Student',
   256→    });
   257→  }
   258→
   259→  // Send typing indicator
   260→  sendTyping(conversationId: string, isTyping: boolean): void {
   261→    if (!this.socket?.connected) return;
   262→
   263→    this.socket.emit('typing', { conversationId, isTyping });
   264→  }
   265→
   266→  // Mark message as read
   267→  markAsRead(messageId: string | null, conversationId: string): void {
   268→    if (!this.socket?.connected) return;
   269→
   270→    this.socket.emit('mark_read', { messageId, conversationId });
   271→  }
   272→
   273→  // Event listener management
